<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Conway's Game of Life</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --text-color: #e0e0e0;
            --accent-color: #4caf50;
            --danger-color: #f44336;
            --grid-bg: #2d2d2d;
            --cell-alive: #4caf50;
            --cell-dead: #1a1a1a;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            overflow: hidden;
        }

        h1 {
            margin-bottom: 1rem;
            font-weight: 300;
            letter-spacing: 2px;
            text-transform: uppercase;
            font-size: 1.5rem;
        }

        #controls {
            display: flex;
            gap: 10px;
            margin-bottom: 15px;
            background: #333;
            padding: 10px;
            border-radius: 8px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        button {
            padding: 8px 16px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            transition: transform 0.1s, opacity 0.2s;
            font-size: 0.9rem;
        }

        button:active {
            transform: scale(0.95);
        }

        #step { background-color: var(--text-color); color: var(--bg-color); }
        #play { background-color: var(--accent-color); color: white; }
        #random { background-color: #2196f3; color: white; }
        #clear { background-color: var(--danger-color); color: white; }

        button.playing {
            border: 2px solid #fff;
            box-shadow: 0 0 8px rgba(76, 175, 80, 0.5);
        }

        #life-container {
            position: relative;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            border-radius: 4px;
            overflow: hidden;
            border: 1px solid #444;
        }

        canvas {
            display: block;
            background-color: var(--grid-bg);
            cursor: crosshair;
        }

        .instructions {
            margin-top: 10px;
            font-size: 0.8rem;
            color: #888;
        }
    </style>
</head>
<body>

    <h1>Conway's Game of Life</h1>

    <div id="controls">
        <button id="step">Step</button>
        <button id="play">Play</button>
        <button id="random">Randomize</button>
        <button id="clear">Clear</button>
    </div>

    <div id="life-container">
        <canvas id="life"></canvas>
    </div>

    <div class="instructions">Click or drag on the grid to paint cells.</div>

<script>
(function() {
    // Configuration
    const CELL_SIZE = 10; // pixels per cell
    const GRID_W = 40;   // number of columns
    const GRID_H = 40;   // number of rows

    // DOM Elements
    const canvas = document.getElementById('life');
    const ctx = canvas.getContext('2d');

    // Setup Canvas Size
    canvas.width = GRID_W * CELL_SIZE;
    canvas.height = GRID_H * CELL_SIZE;

    // State
    let grid = []; // 1D array representing the grid state (0 or 1)
    let isPlaying = false;
    let animationFrameId = null;

    // Interaction State
    let isMouseDown = false;
    let lastMouseX = -1;
    let lastMouseY = -1;

    // Initialize Grid
    function initGrid() {
        grid = new Array(GRID_W * GRID_H).fill(0);
        draw();
    }

    // --- API Implementation (window.life) ---

    window.life = {
        w: GRID_W,
        h: GRID_H,

        get: function(x, y) {
            if (x < 0 || x >= this.w || y < 0 || y >= this.h) return 0;
            const idx = y * this.w + x;
            return grid[idx];
        },

        set: function(x, y, v) {
            if (x < 0 || x >= this.w || y < 0 || y >= this.h) return;
            const idx = y * this.w + x;
            grid[idx] = v ? 1 : 0;
            draw(); // Immediate redraw for interactivity
        },

        step: function() {
            if (isPlaying) return; // Don't auto-step while playing

            // Create a copy of the current grid to ensure simultaneous updates
            const nextGrid = new Array(GRID_W * GRID_H);

            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    const idx = y * GRID_W + x;
                    const currentVal = grid[idx];

                    // Count neighbors
                    let neighbors = 0;

                    // Check 8 surrounding cells
                    for (let dy = -1; dy <= 1; dy++) {
                        for (let dx = -1; dx <= 1; dx++) {
                            if (dx === 0 && dy === 0) continue;

                            const nx = x + dx;
                            const ny = y + dy;

                            // Edges are dead (no wrap-around)
                            if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H) {
                                neighbors += grid[ny * GRID_W + nx];
                            }
                        }
                    }

                    // Apply Rules B3/S23
                    if (currentVal === 1) {
                        // Live cell survives with 2 or 3 neighbors
                        if (neighbors === 2 || neighbors === 3) {
                            nextGrid[idx] = 1;
                        } else {
                            nextGrid[idx] = 0;
                        }
                    } else {
                        // Dead cell becomes alive with exactly 3 neighbors
                        if (neighbors === 3) {
                            nextGrid[idx] = 1;
                        } else {
                            nextGrid[idx] = 0;
                        }
                    }
                }
            }

            grid = nextGrid;
            draw();
        },

        clear: function() {
            initGrid();
        }
    };

    // --- Rendering ---

    function draw() {
        // Clear background
        ctx.fillStyle = '#2d2d2d'; // Grid BG color
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Draw live cells
        ctx.fillStyle = '#4caf50'; // Alive color

        for (let y = 0; y < GRID_H; y++) {
            for (let x = 0; x < GRID_W; x++) {
                const idx = y * GRID_W + x;
                if (grid[idx] === 1) {
                    ctx.fillRect(
                        x * CELL_SIZE, 
                        y * CELL_SIZE, 
                        CELL_SIZE - 1, // -1 for a small gap effect
                        CELL_SIZE - 1
                    );
                }
            }
        }
    }

    // --- Interaction Handlers ---

    function getGridCoords(e) {
        const rect = canvas.getBoundingClientRect();
        const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
        const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
        return { x, y };
    }

    function toggleCell(x, y) {
        // Toggle: if currently 0 -> 1, if 1 -> 0
        const current = window.life.get(x, y);
        window.life.set(x, y, current === 0 ? 1 : 0);
    }

    canvas.addEventListener('mousedown', (e) => {
        isMouseDown = true;
        const coords = getGridCoords(e);
        toggleCell(coords.x, coords.y);
    });

    canvas.addEventListener('mousemove', (e) => {
        if (!isMouseDown) return;
        const coords = getGridCoords(e);

        // Only update if mouse moved to a new cell to avoid flickering
        if (coords.x !== lastMouseX || coords.y !== lastMouseY) {
            toggleCell(coords.x, coords.y);
            lastMouseX = coords.x;
            lastMouseY = coords.y;
        }
    });

    window.addEventListener('mouseup', () => {
        isMouseDown = false;
        lastMouseX = -1;
        lastMouseY = -1;
    });

    // --- Controls Logic ---

    const btnStep = document.getElementById('step');
    const btnPlay = document.getElementById('play');
    const btnRandom = document.getElementById('random');
    const btnClear = document.getElementById('clear');

    btnStep.addEventListener('click', () => {
        window.life.step();
    });

    btnPlay.addEventListener('click', () => {
        if (isPlaying) {
            // Stop playing
            isPlaying = false;
            btnPlay.classList.remove('playing');
            cancelAnimationFrame(animationFrameId);
        } else {
            // Start playing
            isPlaying = true;
            btnPlay.classList.add('playing');

            const loop = () => {
                if (!isPlaying) return;
                window.life.step();
                animationFrameId = requestAnimationFrame(loop);
            };
            loop();
        }
    });

    btnRandom.addEventListener('click', () => {
        // Randomize grid
        for (let i = 0; i < grid.length; i++) {
            grid[i] = Math.random() > 0.85 ? 1 : 0; // ~15% density
        }
        draw();
    });

    btnClear.addEventListener('click', () => {
        window.life.clear();
    });

    // Initialize
    initGrid();

})();
</script>
</body>
</html>
